import org.apache.kafka.clients.producer.ProducerConfig;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.kafka.core.DefaultKafkaProducerFactory;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.kafka.core.ProducerFactory;
import org.springframework.kafka.support.serializer.JsonSerializer;

import java.util.HashMap;
import java.util.Map;

@Configuration
public class KafkaProducerConfig {

    @Value("${spring.kafka.producer.bootstrap-servers}")
    private String bootstrapServers;

    @Value("${spring.kafka.producer.key-serializer}")
    private String keySerializer;

    @Value("${spring.kafka.producer.value-serializer}")
    private String valueSerializer;

    @Bean
    public Map<String, Object> producerConfigs() {
        Map<String, Object> props = new HashMap<>();
        props.put(ProducerConfig.BOOTSTRAP_SERVERS_CONFIG, bootstrapServers);
        props.put(ProducerConfig.KEY_SERIALIZER_CLASS_CONFIG, keySerializer);
        props.put(ProducerConfig.VALUE_SERIALIZER_CLASS_CONFIG, valueSerializer);
        // Add any other producer configurations here
        return props;
    }

    @Bean
    public ProducerFactory<String, EventMessage> producerFactory() {
        return new DefaultKafkaProducerFactory<>(producerConfigs(),
                                                 new org.apache.kafka.common.serialization.StringSerializer(),
                                                 new JsonSerializer<EventMessage>());
    }

    @Bean
    public KafkaTemplate<String, EventMessage> kafkaTemplate() {
        return new KafkaTemplate<>(producerFactory());
    }
}

// KafkaProducerService.java
import org.apache.kafka.clients.producer.ProducerRecord;
import org.apache.kafka.common.header.internals.RecordHeader;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.stereotype.Service;

import java.nio.charset.StandardCharsets;
import java.util.Map;
import java.util.concurrent.CompletableFuture;

@Service
public class KafkaProducerService {

    private final KafkaTemplate<String, EventMessage> kafkaTemplate;

    @Value("${app.kafka.topic}")
    private String topicName;

    public KafkaProducerService(KafkaTemplate<String, EventMessage> kafkaTemplate) {
        this.kafkaTemplate = kafkaTemplate;
    }

    public CompletableFuture<Void> sendMessage(EventMessage message, Map<String, String> customHeaders) {
        ProducerRecord<String, EventMessage> record = new ProducerRecord<>(topicName, message);

        if (customHeaders != null) {
            customHeaders.forEach((key, value) -> {
                if (key != null && value != null) {
                    record.headers().add(new RecordHeader(key, value.getBytes(StandardCharsets.UTF_8)));
                }
            });
        }

        return kafkaTemplate.send(record)
                .completable()
                .thenApply(sendResult -> {
                    System.out.println("Sent message to Kafka topic: " + topicName +
                                       " with offset: " + sendResult.getRecordMetadata().offset() +
                                       " and headers: " + customHeaders);
                    return null;
                })
                .exceptionally(ex -> {
                    System.err.println("Failed to send message to Kafka: " + ex.getMessage());
                    throw new RuntimeException("Kafka send failed", ex);
                });
    }
}

// EventController.java
import jakarta.servlet.http.HttpServletRequest;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestHeader;
import org.springframework.web.bind.annotation.RestController;

import java.util.Enumeration;
import java.util.HashMap;
import java.util.Map;
import java.util.concurrent.CompletableFuture;

@RestController
public class EventController {

    private final KafkaProducerService kafkaProducerService;

    public EventController(KafkaProducerService kafkaProducerService) {
        this.kafkaProducerService = kafkaProducerService;
    }

    @PostMapping("/track-event")
    public CompletableFuture<ResponseEntity<String>> trackEvent(
            @RequestBody EventMessage event,
            @RequestHeader(value = "tracking-id", required = false) String trackingId,
            @RequestHeader(value = "user-id", required = false) String userId,
            @RequestHeader(value = "custom-metadata", required = false) String customMetadataJson, // Expecting JSON string
            HttpServletRequest request // To capture other dynamic headers
    ) {
        Map<String, String> customHeaders = new HashMap<>();

        // Add explicitly requested headers
        if (trackingId != null) {
            customHeaders.put("tracking-id", trackingId);
        }
        if (userId != null) {
            customHeaders.put("user-id", userId);
        }
        if (customMetadataJson != null) {
            customHeaders.put("custom-metadata", customMetadataJson);
        }

        // Add any other custom headers prefixed with "X-"
        Enumeration<String> headerNames = request.getHeaderNames();
        while (headerNames.hasMoreElements()) {
            String headerName = headerNames.nextElement();
            if (headerName.toLowerCase().startsWith("x-")) { // Example: X-Correlation-ID, X-Client-IP
                customHeaders.put(headerName, request.getHeader(headerName));
            }
        }

        return kafkaProducerService.sendMessage(event, customHeaders)
                .thenApply(v -> new ResponseEntity<>("Event tracked successfully!", HttpStatus.OK))
                .exceptionally(ex -> new ResponseEntity<>("Failed to track event: " + ex.getMessage(), HttpStatus.INTERNAL_SERVER_ERROR));
    }
}